<?php declare(strict_types=1);require __DIR__.'/../includes/functions.php';
class Car{public function __construct(public string $brand,public string $color){}public function showInfo():string{return "Hãng xe: {$this->brand} — Màu sắc: {$this->color}";}}
$cars=[];$error='';if($_SERVER['REQUEST_METHOD']==='POST'){$v=[];foreach(['brand1','color1','brand2','color2'] as $k)$v[$k]=trim((string)($_POST[$k]??''));if(in_array('',$v,true))$error='Vui lòng nhập đầy đủ thông tin cho hai xe.';else $cars=[new Car($v['brand1'],$v['color1']),new Car($v['brand2'],$v['color2'])];}
$pageTitle='Bài 01 - Class Car';$basePath='..';$current='bai01';require __DIR__.'/../includes/header.php';?>
<div class="crumb"><a href="../index.php">Trang chủ</a> / Bài 01</div><h1>Class Car</h1><p class="subtitle">Tạo hai đối tượng Car và gọi phương thức showInfo().</p><div class="two"><section class="card"><h2>Thông tin xe</h2><?php if($error):?><div class="alert err"><?=e($error)?></div><?php endif;?><form method="post"><div class="form-grid"><div class="group"><label>Hãng xe 1</label><input name="brand1" value="<?=old('brand1','Toyota')?>" required></div><div class="group"><label>Màu xe 1</label><input name="color1" value="<?=old('color1','Đỏ')?>" required></div><div class="group"><label>Hãng xe 2</label><input name="brand2" value="<?=old('brand2','Honda')?>" required></div><div class="group"><label>Màu xe 2</label><input name="color2" value="<?=old('color2','Xanh')?>" required></div></div><div class="actions"><button class="btn primary">Tạo đối tượng</button></div></form></section><aside class="card"><div class="result"><h2>Kết quả</h2><?php if($cars):foreach($cars as $i=>$car):?><div class="item"><strong>Xe <?=$i+1?></strong><div class="muted"><?=e($car->showInfo())?></div></div><?php endforeach;else:?><p class="muted">Chưa có dữ liệu.</p><?php endif;?></div></aside></div><?php require __DIR__.'/../includes/footer.php';?>
